import { backendApiUrl } from "@/lib/seo";
import { isNonSelfCanonical } from "@/lib/seo";

export type PublicBlogPost = {
  slug: string;
  title: string;
  h1?: string | null;
  content_md: string;
  content_json?: Record<string, unknown> | null;
  content_version?: number;
  excerpt?: string | null;
  cover_image_url?: string | null;
  cover_image_width?: number;
  cover_image_height?: number;
  author?: string | null;
  meta_title?: string | null;
  meta_description?: string | null;
  canonical_url?: string | null;
  og_title?: string | null;
  og_description?: string | null;
  og_image_url?: string | null;
  cover_image_alt?: string | null;
  robots_index?: boolean;
  robots_follow?: boolean;
  include_in_sitemap?: boolean;
  author_slug?: string | null;
  locale: "en" | "ru";
  published_at: string;
  updated_at?: string | null;
  available_locales?: string[] | null;
};

export async function getPublishedBlogPosts(locale: "en" | "ru", pageSize = 100) {
  try {
    const response = await fetch(
      `${backendApiUrl()}/api/public/blog?locale=${locale}&page_size=${pageSize}`,
      {
        next: { revalidate: 60 },
        signal: AbortSignal.timeout(2_000),
      },
    );
    if (!response.ok) return [];
    const data = (await response.json()) as { items?: PublicBlogPost[] };
    return (data.items ?? []).filter(
      (post) =>
        !isNonSelfCanonical(
          post.canonical_url,
          `/${locale}/blog/${post.slug}`,
        ),
    );
  } catch {
    return [];
  }
}

export type BlogPostLookup =
  | { status: "ok"; post: PublicBlogPost }
  | { status: "not_found" }
  // The CMS backend errored or timed out: the article may well exist, so
  // callers must NOT serve a hard 404 (crawlers would deindex it).
  | { status: "unavailable" };

export async function lookupPublishedBlogPost(
  slug: string,
  locale: "en" | "ru",
): Promise<BlogPostLookup> {
  try {
    const response = await fetch(
      `${backendApiUrl()}/api/public/blog/${encodeURIComponent(slug)}?locale=${locale}`,
      {
        next: { revalidate: 60 },
        signal: AbortSignal.timeout(2_000),
      },
    );
    if (response.status === 404) return { status: "not_found" };
    if (!response.ok) return { status: "unavailable" };
    return { status: "ok", post: (await response.json()) as PublicBlogPost };
  } catch {
    return { status: "unavailable" };
  }
}

export async function getPublishedBlogPost(
  slug: string,
  locale: "en" | "ru",
) {
  const lookup = await lookupPublishedBlogPost(slug, locale);
  return lookup.status === "ok" ? lookup.post : null;
}
